import{Logger}from '../../shared/logger.js';import{loadNotes,saveNotes,createNote,updateNote,deleteNote,reorderNotes}from './notes-storage.js';import{renderNote,renderEmptyState,escapeHtml}from './notes-renderer.js';import{createWidget,toggleCollapse,getWidget,getNotesList,showEmptyState,hideEmptyState,renderNotesList}from './notes-widget.js';import{openEditModal,closeModal}from './notes-modal.js';import{initDragAndDrop}from './notes-dnd.js';import{getRandomColor,WIDGET_ID}from './notes-constants.js';import{addWidgetStyles}from './notes-styles.js';let notes=[];export function initQuickNotes(){notes=loadNotes();createWidget();addWidgetStyles();attachWidgetListeners();renderNotes();document.addEventListener('quick-notes:open',()=>createNewNote());document.addEventListener('quick-notes:reorder',handleReorder);Logger.info('[QuickNotes] Initialized');}function attachWidgetListeners(){const widget=getWidget();if(!widget)return;widget.querySelector('.quick-notes-add')?.addEventListener('click',createNewNote);widget.querySelector('.quick-notes-collapse')?.addEventListener('click',toggleCollapse);widget.querySelector('.quick-notes-create')?.addEventListener('click',createNewNote);}export function renderNotes(){const list=getNotesList();if(!list)return;if(notes.length===0){showEmptyState();}else{hideEmptyState();list.innerHTML=notes.map((note,index)=>renderNote(note,index)).join('');list.querySelectorAll('.quick-note-item').forEach(item=>{const noteId=item.dataset.id;attachNoteListeners(item,noteId);});}}function attachNoteListeners(item,noteId){const editBtn=item.querySelector('.quick-note-edit');const deleteBtn=item.querySelector('.quick-note-delete');editBtn?.addEventListener('click',(e)=>{e.stopPropagation();editNote(noteId);});deleteBtn?.addEventListener('click',(e)=>{e.stopPropagation();deleteNoteById(noteId);});item.addEventListener('click',()=>editNote(noteId));initDragAndDrop(item,noteId);}export function createNewNote(){const note=createNote('',getRandomColor());notes.unshift(note);saveNotes(notes);renderNotes();openEditModal(note,(content,color)=>{const updated=updateNote(notes,note.id,{content,color});notes=updated;saveNotes(notes);renderNotes();Logger.info('[QuickNotes] Created note:',note.id);},()=>{deleteNoteById(note.id);});}function editNote(noteId){const note=notes.find(n=>n.id===noteId);if(!note)return;openEditModal(note,(content,color)=>{const updated=updateNote(notes,noteId,{content,color});notes=updated;saveNotes(notes);renderNotes();Logger.info('[QuickNotes] Updated note:',noteId);},()=>{deleteNoteById(noteId);});}function deleteNoteById(noteId){if(!confirm('Bạn có chắc chắn muốn xóa ghi chú này?'))return;notes=deleteNote(notes,noteId);saveNotes(notes);renderNotes();Logger.info('[QuickNotes] Deleted note:',noteId);}function handleReorder(event){const{draggedId,targetId,insertBefore}=event.detail;notes=reorderNotes(notes,draggedId,targetId,insertBefore);saveNotes(notes);renderNotes();}export function getNotes(){return [...notes];}export function getNoteById(noteId){return notes.find(n=>n.id===noteId)||null;}export function clearNotes(){notes=[];saveNotes(notes);renderNotes();}if(typeof window!=='undefined'){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initQuickNotes);}else{initQuickNotes();}}